  1	import * as React from 'react';
  2	import { OSDMigrationStatus } from '@odf/core/constants';
  3	import { PROVIDER_MODE } from '@odf/core/features';
  4	import { useGetInternalClusterDetails } from '@odf/core/redux/utils';
  5	import {
  6	  getStorageClusterInNs,
  7	  getResourceInNs as getCephClusterInNs,
  8	} from '@odf/core/utils';
  9	import { getOSDMigrationStatus } from '@odf/ocs/utils';
 10	import { OCS_OPERATOR } from '@odf/shared/constants';
 11	import { DataResiliency } from '@odf/shared/dashboards/data-resiliency/data-resiliency-activity';
 12	import {
 13	  useCustomPrometheusPoll,
 14	  usePrometheusBasePath,
 15	} from '@odf/shared/hooks/custom-prometheus-poll';
 16	import { useDeepCompareMemoize } from '@odf/shared/hooks/deep-compare-memoize';
 17	import { CephClusterModel, StorageClusterModel } from '@odf/shared/models';
 18	import { EventModel, PersistentVolumeClaimModel } from '@odf/shared/models';
 19	import { subscriptionResource } from '@odf/shared/resources/common';
 20	import { getAnnotations, getName } from '@odf/shared/selectors';
 21	import {
 22	  K8sResourceKind,
 23	  PersistentVolumeClaimKind,
 24	  SubscriptionKind,
 25	  StorageClusterKind,
 26	  CephClusterKind,
 27	} from '@odf/shared/types';
 28	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 29	import {
 30	  getResiliencyProgress,
 31	  isCephProvisioner,
 32	  referenceForModel,
 33	} from '@odf/shared/utils';
 34	import { useFlag } from '@openshift-console/dynamic-plugin-sdk';
 35	import { useK8sWatchResource } from '@openshift-console/dynamic-plugin-sdk';
 36	import { EventKind } from '@openshift-console/dynamic-plugin-sdk/lib/api/internal-types';
 37	import {
 38	  ActivityBody,
 39	  OngoingActivityBody,
 40	  RecentEventsBody,
 41	} from '@openshift-console/dynamic-plugin-sdk-internal';
 42	import * as _ from 'lodash-es';
 43	import { Card, CardHeader, CardTitle, CardBody } from '@patternfly/react-core';
 44	import { PVC_PROVISIONER_ANNOTATION } from '../../../constants';
 45	import {
 46	  DATA_RESILIENCY_QUERY,
 47	  StorageDashboardQuery,
 48	} from '../../../queries/ceph-storage';
 49	import { isPersistentStorageEvent } from '../../../utils/common';
 50	import {
 51	  isClusterExpandActivity,
 52	  ClusterExpandActivity,
 53	} from './cluster-expand-activity';
 54	import { ClusterMigrationActivity } from './cluster-migration-activity';
 55	import {
 56	  isSubscriptionUpgradeActivity,
 57	  OCSUpgradeActivity,
 58	} from './ocs-upgrade-activity';
 59	import '../../../style.scss';
 60	import './activity-card.scss';
 61	
 62	export const getOCSSubscription = (
 63	  subscriptions: K8sResourceKind[]
 64	): SubscriptionKind =>
 65	  _.find(
 66	    subscriptions,
 67	    (item) => item?.spec?.name === OCS_OPERATOR
 68	  ) as SubscriptionKind;
 69	
 70	export const pvcResource = {
 71	  isList: true,
 72	  kind: PersistentVolumeClaimModel.kind,
 73	};
 74	
 75	export const eventsResource = {
 76	  isList: true,
 77	  kind: EventModel.kind,
 78	};
 79	
 80	const cephClusterResource = {
 81	  kind: referenceForModel(CephClusterModel),
 82	  isList: true,
 83	};
 84	
 85	const RecentEvent: React.FC = () => {
 86	  const { clusterNamespace: clusterNs } = useGetInternalClusterDetails();
 87	  const [pvcs, pvcLoaded] =
 88	    useK8sWatchResource<PersistentVolumeClaimKind[]>(pvcResource);
 89	  const [events, eventsLoaded] =
 90	    useK8sWatchResource<EventKind[]>(eventsResource);
 91	
 92	  const validPVC = pvcs
 93	    .filter((obj) =>
 94	      isCephProvisioner(getAnnotations(obj)?.[PVC_PROVISIONER_ANNOTATION])
 95	    )
 96	    .map(getName);
 97	  const memoizedPVCNames = useDeepCompareMemoize(validPVC, true);
 98	
 99	  const ocsEventsFilter = React.useCallback(
100	    () => isPersistentStorageEvent(memoizedPVCNames, clusterNs),
101	    [memoizedPVCNames, clusterNs]
102	  );
103	
104	  const eventObject = {
105	    data: events,
106	    loaded: eventsLoaded && pvcLoaded,
107	    kind: 'Event',
108	    loadError: null,
109	  };
110	
111	  return <RecentEventsBody events={eventObject} filter={ocsEventsFilter()} />;
112	};
113	
114	export const storageClusterResource = {
115	  isList: true,
116	  kind: referenceForModel(StorageClusterModel),
117	};
118	
119	const OngoingActivity = () => {
120	  const { clusterNamespace: clusterNs, clusterName: managedByOCS } =
121	    useGetInternalClusterDetails();
122	
123	  const [subscriptions, subLoaded] =
124	    useK8sWatchResource<K8sResourceKind[]>(subscriptionResource);
125	  const [clusters, clusterLoaded] = useK8sWatchResource<StorageClusterKind[]>(
126	    storageClusterResource
127	  );
128	
129	  const [cephClusters, cephClustersLoaded] =
130	    useK8sWatchResource<CephClusterKind[]>(cephClusterResource);
131	
132	  // Only single cluster per Namespace.
133	  const cephCluster: CephClusterKind = getCephClusterInNs(
134	    cephClusters,
135	    clusterNs
136	  );
137	
138	  const [resiliencyMetric, , metricsLoading] = useCustomPrometheusPoll({
139	    query:
140	      DATA_RESILIENCY_QUERY(managedByOCS)[
141	        StorageDashboardQuery.RESILIENCY_PROGRESS
142	      ],
143	    endpoint: 'api/v1/query' as any,
144	    basePath: usePrometheusBasePath(),
145	  });
146	
147	  const ocsSubscription: SubscriptionKind = getOCSSubscription(subscriptions);
148	
149	  const ocsCluster: K8sResourceKind = getStorageClusterInNs(
150	    clusters,
151	    clusterNs
152	  );
153	
154	  const prometheusActivities = [];
155	  const resourceActivities = [];
156	
157	  if (getResiliencyProgress(resiliencyMetric) < 1) {
158	    prometheusActivities.push({
159	      results: resiliencyMetric,
160	      component: DataResiliency,
161	    });
162	  }
163	
164	  if (isSubscriptionUpgradeActivity(ocsSubscription)) {
165	    resourceActivities.push({
166	      resource: ocsSubscription,
167	      timestamp: ocsSubscription?.status?.lastUpdated,
168	      component: OCSUpgradeActivity,
169	    });
170	  }
171	
172	  if (isClusterExpandActivity(ocsCluster)) {
173	    resourceActivities.push({
174	      resource: ocsCluster,
175	      timestamp: null,
176	      component: ClusterExpandActivity,
177	    });
178	  }
179	
180	  const isProviderMode = useFlag(PROVIDER_MODE);
181	  const osdMigrationStatus = getOSDMigrationStatus(cephCluster);
182	
183	  // Checks for migration progress and displays a message if migration is in progress.
184	  // If migration is complete, the UI remains empty.
185	  if (
186	    !isProviderMode &&
187	    [OSDMigrationStatus.PENDING, OSDMigrationStatus.IN_PROGRESS].includes(
188	      osdMigrationStatus
189	    )
190	  ) {
191	    resourceActivities.push({
192	      resource: cephCluster,
193	      timestamp: null,
194	      component: ClusterMigrationActivity,
195	    });
196	  }
197	
198	  return (
199	    <OngoingActivityBody
200	      loaded={
201	        subLoaded && cephClustersLoaded && clusterLoaded && !metricsLoading
202	      }
203	      resourceActivities={resourceActivities}
204	      prometheusActivities={prometheusActivities}
205	    />
206	  );
207	};
208	
209	export const ActivityCard: React.FC = React.memo(() => {
210	  const { t } = useCustomTranslation();
211	
212	  return (
213	    <Card className="odf-overview-card--gradient">
214	      <CardHeader>
215	        <CardTitle>{t('Activity')}</CardTitle>
216	      </CardHeader>
217	      <CardBody>
218	        <ActivityBody className="ceph-activity-card__body">
219	          <OngoingActivity />
220	          <RecentEvent />
221	        </ActivityBody>
222	      </CardBody>
223	    </Card>
224	  );
225	});
226	
227	ActivityCard.displayName = 'ActivityCard';
228	
229	export default ActivityCard;

